// Normaliza todos los campos al esquema estándar
// Limpia espacios, normaliza emails a lowercase, formatea birthday para Mailchimp
const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;

  const email = (raw.email || '').trim().toLowerCase();

  // Normalizar birthday a formato MM/DD (requerido por Mailchimp)
  let birthday = '';
  if (raw.birthday) {
    const d = new Date(raw.birthday);
    if (!isNaN(d.getTime())) {
      birthday = String(d.getUTCMonth() + 1).padStart(2, '0') + '/' + String(d.getUTCDate()).padStart(2, '0');
    }
  }

  results.push({
    json: {
      email,
      first_name: (raw.first_name || '').trim(),
      last_name: (raw.last_name || '').trim(),
      phone: (raw.phone || '').trim(),
      birthday,
      birthday_raw: raw.birthday || '',
      zone: (raw.zone || '').trim(),
      city: (raw.city || '').trim(),
      country: (raw.country || '').trim(),
      customer_type: (raw.customer_type || '').trim().toLowerCase(),
      role: (raw.role || '').trim().toLowerCase(),
      representative: (raw.representative || '').trim(),
      status: (raw.status || '').trim().toLowerCase(),
      tags: Array.isArray(raw.tags) ? raw.tags.map(t => String(t).trim().toLowerCase()) : [],
      merge_fields: raw.merge_fields || {},
      source_system: (raw.source_system || '').trim(),
      updated_at: raw.updated_at || '',
      external_id: raw.external_id || ''
    }
  });
}

return results;

// Valida emails, detecta duplicados, separa inválidos
const items = $input.all();
const seen = new Set();
const valid = [];
const invalid = [];

for (const item of items) {
  const c = item.json;

  // Validar formato de email
  if (!c.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(c.email)) {
    invalid.push({ ...c, _reason: 'email_invalido' });
    continue;
  }

  // Deduplicar por email
  if (seen.has(c.email)) {
    invalid.push({ ...c, _reason: 'duplicado' });
    continue;
  }
  seen.add(c.email);

  valid.push(c);
}

return [{ json: {
  valid,
  invalid,
  stats: { total_input: items.length, valid: valid.length, invalid: invalid.length }
} }];

// Compara contactos validados contra la audiencia de Mailchimp
// Clasifica en: toCreate, toUpdate, toUnsubscribe, unchanged
const { valid, invalid } = $('Validate & Deduplicate').first().json;

// El nodo nativo Mailchimp getAll devuelve un item por miembro
const mcMembers = $('Mailchimp: Get Audience').all().map(i => i.json);

// Mapa de Mailchimp indexado por email
const mcMap = new Map();
for (const m of mcMembers) {
  mcMap.set(m.email_address.toLowerCase(), m);
}

const sourceEmails = new Set(valid.map(c => c.email));
const toCreate = [];
const toUpdate = [];
const toUnsubscribe = [];
const unchanged = [];

for (const contact of valid) {
  const existing = mcMap.get(contact.email);

  if (!existing) {
    toCreate.push(contact);
    continue;
  }

  // Comparar merge fields para detectar cambios
  const mf = existing.merge_fields || {};
  const needsUpdate =
    (contact.first_name && contact.first_name !== (mf.FNAME || '')) ||
    (contact.last_name && contact.last_name !== (mf.LNAME || '')) ||
    (contact.phone && contact.phone !== (mf.PHONE || '')) ||
    (contact.birthday && contact.birthday !== (mf.BIRTHDAY || '')) ||
    (contact.zone && contact.zone !== (mf.ZONE || '')) ||
    (contact.city && contact.city !== (mf.CITY || '')) ||
    (contact.country && contact.country !== (mf.COUNTRY || '')) ||
    (contact.customer_type && contact.customer_type !== (mf.CTYPE || '')) ||
    (contact.role && contact.role !== (mf.ROLE || '')) ||
    (contact.representative && contact.representative !== (mf.REP || ''));

  if (needsUpdate) {
    toUpdate.push({ ...contact, _mailchimp_id: existing.id });
  } else {
    unchanged.push(contact);
  }
}

// Contactos en Mailchimp que no están en la fuente y están suscritos
for (const [email, member] of mcMap) {
  if (!sourceEmails.has(email) && member.status === 'subscribed') {
    toUnsubscribe.push({
      email,
      first_name: member.merge_fields?.FNAME || '',
      last_name: member.merge_fields?.LNAME || '',
      _mailchimp_id: member.id,
      _current_status: member.status
    });
  }
}

const summary = {
  source_total: valid.length,
  mailchimp_total: mcMembers.length,
  to_create: toCreate.length,
  to_update: toUpdate.length,
  to_unsubscribe: toUnsubscribe.length,
  unchanged: unchanged.length,
  invalid: invalid.length,
  timestamp: new Date().toISOString()
};

return [{ json: { toCreate, toUpdate, toUnsubscribe, unchanged, invalid, summary } }];

// Reporte detallado de preview sin ejecutar cambios
const data = $('Compare & Classify').first().json;

return [{ json: {
  mode: 'DRY RUN — Sin cambios aplicados en Mailchimp',
  summary: data.summary,
  detail: {
    to_create: {
      count: data.toCreate.length,
      samples: data.toCreate.slice(0, 5).map(c => ({
        email: c.email,
        name: c.first_name + ' ' + c.last_name,
        zone: c.zone,
        type: c.customer_type,
        tags: c.tags
      }))
    },
    to_update: {
      count: data.toUpdate.length,
      samples: data.toUpdate.slice(0, 5).map(c => ({
        email: c.email,
        name: c.first_name + ' ' + c.last_name
      }))
    },
    to_unsubscribe: {
      count: data.toUnsubscribe.length,
      samples: data.toUnsubscribe.slice(0, 5).map(c => ({
        email: c.email,
        name: c.first_name + ' ' + c.last_name
      }))
    },
    unchanged: { count: data.unchanged.length },
    invalid: {
      count: data.invalid.length,
      samples: data.invalid.slice(0, 5).map(c => ({
        email: c.email || '(vacío)',
        reason: c._reason
      }))
    }
  },
  next_step: 'Para ejecutar cambios reales, cambiar DRY_RUN a false en Config y volver a ejecutar'
} }];

// Prepara items individuales para los nodos nativos de Mailchimp
// Cada item lleva los datos del contacto + _action para el Switch
const data = $('Compare & Classify').first().json;

const items = [];

// Items para crear
for (const c of data.toCreate) {
  items.push({ json: {
    ...c,
    _action: 'create',
    tags_csv: (c.tags || []).join(',')
  }});
}

// Items para actualizar
for (const c of data.toUpdate) {
  items.push({ json: {
    ...c,
    _action: 'update'
  }});
}

// Items para desuscribir
for (const c of data.toUnsubscribe) {
  items.push({ json: {
    ...c,
    _action: 'unsubscribe'
  }});
}

// Item de reporte (garantiza que Build Report se ejecute siempre)
items.push({ json: {
  _action: 'report',
  summary: data.summary,
  creates_sent: data.toCreate.length,
  updates_sent: data.toUpdate.length,
  unsubscribes_sent: data.toUnsubscribe.length,
  unchanged_count: data.unchanged.length,
  invalid_count: data.invalid.length
}});

return items;

// Reporte final de ejecución
const data = $input.first().json;

return [{ json: {
  mode: 'APPLY — Cambios enviados a Mailchimp',
  summary: data.summary,
  actions_sent: {
    creates: data.creates_sent,
    updates: data.updates_sent,
    unsubscribes: data.unsubscribes_sent,
    unchanged: data.unchanged_count,
    invalid: data.invalid_count
  },
  note: 'Revisar la salida de cada nodo Mailchimp (Create/Update/Unsubscribe) en el historial de ejecución para ver resultados individuales',
  timestamp: new Date().toISOString()
} }];
